queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?requirement_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:requirement_id ?cg . ?child a :Requirements ; p:id ?cg . ?l p:job_posting_id ?pg . ?parent a :JobPostings ; p:id ?pg . } GROUP BY ?child }
  ?child p:requirement_type ?requirement_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :JobPostings } }
  FILTER(?nf = ?total)
}

